from flask import Flask, request, redirect, url_for, session, render_template_string
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Dummy database for demonstration purposes
users = {
    'user1': {'password': 'password1', 'mfa_secret': 'secret1'}
}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users and users[username]['password'] == password:
            session['username'] = username
            return redirect(url_for('verify_mfa'))
        else:
            return 'Invalid credentials'
    return render_template_string('''
        <form method="post">
            Username: <input type="text" name="username"><br>
            Password: <input type="password" name="password"><br>
            <input type="submit" value="Login">
        </form>
    ''')

@app.route('/verify-mfa', methods=['GET'])
def verify_mfa():
    if 'username' not in session:
        return redirect(url_for('login'))
    
    username = session['username']
    mfa_code = request.args.get('code')
    
    # Dummy MFA verification logic
    if mfa_code == users[username]['mfa_secret']:
        return redirect(url_for('protected_resource'))
    else:
        return 'Invalid MFA code'

@app.route('/protected-resource')
def protected_resource():
    if 'username' not in session:
        return redirect(url_for('login'))
    
    username = session['username']
    return f'Welcome, {username}! This is a protected resource.'

